class Solution {
public:
    int numTilings(int n) {
        if(n <= 2){return n;}
        if(n == 3){return 5;}
        vector<int> dp(n , 0);
        dp[0] = 1; dp[1] = 2; dp[2] = 5;

        const unsigned int M = 1000000007;

        for(int i = 3; i < n; i++){
            dp[i] = dp[i-1]%M * 2 + dp[i-3]%M;
        }

        return dp[n-1];
    }
};

